      ctx.closePath();
      ctx.fill();

      if (player.doubleShotTimer > 0) {
        ctx.strokeStyle = '#60a5fa';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc(0, 4, 18 + Math.sin(Date.now() * 0.01) * 2, 0, Math.PI * 2);
        ctx.stroke();
      }
      ctx.restore();
    }

    function renderEnemy(e) {
      ctx.save();
      ctx.translate(e.x, e.y);
      const color = e.type === 'elite' ? '#f59e0b' : '#ef4444';
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.moveTo(0, 14);
      ctx.lineTo(14, -10);
      ctx.lineTo(5, -14);
      ctx.lineTo(0, -6);
      ctx.lineTo(-5, -14);
      ctx.lineTo(-14, -10);
      ctx.closePath();
      ctx.fill();

      ctx.fillStyle = '#fff';
      ctx.fillRect(-6, -2, 4, 4);
      ctx.fillRect(2, -2, 4, 4);
      ctx.restore();
    }

    function renderBoss() {
      if (!boss) return;
      ctx.save();
      ctx.translate(boss.x, boss.y);

      const pulseScale = 1 + Math.sin(boss.pulse) * 0.04;
      ctx.scale(pulseScale, pulseScale);

      drawRoundedRect(-boss.width / 2, -boss.height / 2, boss.width, boss.height, 14, '#7c3aed');
      drawRoundedRect(-boss.width / 2 + 8, -boss.height / 2 + 8, boss.width - 16, boss.height - 16, 12, '#a855f7');

      ctx.fillStyle = '#fff';
      ctx.fillRect(-24, -6, 10, 10);
      ctx.fillRect(14, -6, 10, 10);
      ctx.fillStyle = '#0f1020';
      ctx.fillRect(-20, -2, 4, 4);
      ctx.fillRect(18, -2, 4, 4);

      ctx.fillStyle = '#fca5a5';
      ctx.fillRect(-12, 16, 24, 4);

      ctx.restore();

      const barW = 220;
      const barH = 12;
      const x = (GAME_WIDTH - barW) / 2;
      const y = 70;
      drawRoundedRect(x, y, barW, barH, 8, 'rgba(255,255,255,0.12)');
      drawRoundedRect(x, y, barW * Math.max(0, boss.hp / boss.maxHp), barH, 8, '#ff5ea8');
      ctx.fillStyle = '#ffffff';
      ctx.font = '12px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('BOSS', GAME_WIDTH / 2, y - 6);
    }

    function renderHUD() {
      ctx.fillStyle = '#ffffff';
      ctx.textAlign = 'center';
      ctx.font = 'bold 18px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText('得分', GAME_WIDTH / 2, 30);

      ctx.fillStyle = '#4fd1c5';
      ctx.font = 'bold 26px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText(score, GAME_WIDTH / 2, 58);

      ctx.textAlign = 'left';
      ctx.fillStyle = 'rgba(255,255,255,0.9)';
      ctx.font = '14px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText('关卡 ' + level, 16, 28);
      ctx.fillText('最高 ' + highScore, 16, 48);

      const hpX = 16;
      const hpY = 82;
      for (let i = 0; i < player.maxHp; i++) {
        ctx.fillStyle = i < player.hp ? '#4fd1c5' : 'rgba(255,255,255,0.15)';
        ctx.beginPath();
        ctx.moveTo(hpX + i * 20 + 7, hpY);
        ctx.arc(hpX + i * 20 + 4, hpY, 4, Math.PI, 0);
        ctx.arc(hpX + i * 20 + 10, hpY, 4, Math.PI, 0);
        ctx.lineTo(hpX + i * 20 + 7, hpY + 10);
        ctx.closePath();
        ctx.fill();
      }

      if (!bossPhase && gameState === 'playing') {
        ctx.textAlign = 'right';
        ctx.fillStyle = 'rgba(255,255,255,0.85)';
        ctx.fillText('Boss进度 ' + levelProgress + '/' + killsNeeded, GAME_WIDTH - 16, 28);
      }

      if (player.doubleShotTimer > 0) {
        drawRoundedRect(GAME_WIDTH - 112, 42, 96, 24, 12, 'rgba(96,165,250,0.18)', 'rgba(96,165,250,0.5)');
        ctx.textAlign = 'center';
        ctx.fillStyle = '#60a5fa';
        ctx.font = '12px PingFang SC, Microsoft YaHei, sans-serif';
        ctx.fillText('双发 ' + player.doubleShotTimer.toFixed(1) + 's', GAME_WIDTH - 64, 58);
      }
    }

    function renderOverlay(title, subtitle, footer) {
      ctx.fillStyle = 'rgba(0,0,0,0.45)';
      ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

      drawRoundedRect(28, 180, GAME_WIDTH - 56, 240, 12, 'rgba(255,255,255,0.08)', 'rgba(255,255,255,0.14)');
      ctx.textAlign = 'center';
      ctx.fillStyle = '#ffffff';
      ctx.font = 'bold 28px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText(title, GAME_WIDTH / 2, 240);

      ctx.font = '16px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillStyle = 'rgba(255,255,255,0.9)';
      const lines = subtitle.split('\n');
      lines.forEach((line, idx) => {
        ctx.fillText(line, GAME_WIDTH / 2, 285 + idx * 26);
      });

      drawRoundedRect(80, 348, 200, 44, 12, 'rgba(79,209,197,0.18)', 'rgba(79,209,197,0.6)');
      ctx.fillStyle = '#4fd1c5';
      ctx.font = 'bold 18px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText(footer, GAME_WIDTH / 2, 376);
    }

    function renderLevelTransition() {
      if (levelTransitionTimer <= 0) return;
      ctx.save();
      ctx.globalAlpha = Math.min(1, levelTransitionTimer / 0.5);
      drawRoundedRect(70, 250, 220, 70, 12, 'rgba(255,255,255,0.08)', 'rgba(255,255,255,0.15)');
      ctx.textAlign = 'center';
      ctx.fillStyle = '#4fd1c5';
      ctx.font = 'bold 24px PingFang SC, Microsoft YaHei, sans-serif';
      ctx.fillText('进入第 ' + (level + 1) + ' 关', GAME_WIDTH / 2, 294);
      ctx.restore();
    }

    function render() {
      ctx.clearRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

      const gradient = ctx.createLinearGradient(0, 0, 0, GAME_HEIGHT);
      gradient.addColorStop(0, '#1a1a2e');
      gradient.addColorStop(1, '#16213e');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

      let shakeX = 0, shakeY = 0;
      if (screenShake > 0) {
        shakeX = (Math.random() - 0.5) * screenShake;
        shakeY = (Math.random() - 0.5) * screenShake;
      }

      ctx.save();
      ctx.translate(shakeX, shakeY);

      for (const s of stars) {
        ctx.globalAlpha = s.a;
        ctx.fillStyle = '#ffffff';
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.globalAlpha = 1;

      for (const p of particles) {
        ctx.globalAlpha = Math.max(0, p.life / p.maxLife);
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.globalAlpha = 1;

      for (const b of bullets) {
        ctx.fillStyle = '#4fd1c5';
        drawRoundedRect(b.x - b.width / 2, b.y - b.height / 2, b.width, b.height, 2, '#4fd1c5');
      }

      for (const b of enemyBullets) {
        ctx.fillStyle = b.color;
        ctx.beginPath();
        ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
        ctx.fill();
      }

      for (const p of powerups) {
        const color = p.type === 'heal' ? '#4fd1c5' : '#60a5fa';
        drawRoundedRect(p.x - p.width / 2, p.y - p.height / 2, p.width, p.height, 6, color);
        ctx.fillStyle = '#0f1020';
        ctx.textAlign = 'center';
        ctx.font = 'bold 12px PingFang SC, Microsoft YaHei, sans-serif';
        ctx.fillText(p.type === 'heal' ? '+' : 'D', p.x, p.y + 4);
      }

      for (const e of enemies) renderEnemy(e);
      renderBoss();
      renderPlayer();

      ctx.restore();

      renderHUD();
      renderLevelTransition();

      if (gameState === 'menu') {
        renderOverlay(
          'Boss 闯关射击',
          '左右移动并自动连发\n每关击败足够敌人后出现 Boss\n击败 Boss 进入下一关',
          '按 空格 / 点击右下开始'
        );
      } else if (gameState === 'paused') {
        renderOverlay(
          '已暂停',
          '按 P 键继续游戏\n也可点击右上暂停按钮',
          '继续'
        );
      } else if (gameState === 'gameover') {
        renderOverlay(
          '游戏结束',
          '最终得分：' + score + '\n到达关卡：' + level + '\n最高分：' + highScore,
          '按 空格 重新开始'
        );
      }
    }

    function handleInput(key, pressed) {
      if (key in input) input[key] = pressed;

      if (pressed) {
        if ((gameState === 'menu' || gameState === 'gameover') && (key === 'Space')) {
          resetGame();
          gameState = 'playing';
        } else if (key === 'KeyP') {
          if (gameState === 'playing') gameState = 'paused';
          else if (gameState === 'paused') gameState = 'playing';
        }
      }
    }

    window.addEventListener('keydown', (e) => {
      const code = e.code;
      if (['ArrowLeft', 'ArrowRight', 'Space', 'KeyP'].includes(code)) {
        e.preventDefault();
        handleInput(code, true);
      }
    });

    window.addEventListener('keyup', (e) => {
      const code = e.code;
      if (['ArrowLeft', 'ArrowRight', 'Space', 'KeyP'].includes(code)) {
        e.preventDefault();
        handleInput(code, false);
      }
    });

    document.querySelectorAll('.btn').forEach(btn => {
      const key = btn.dataset.key;
      const press = (ev) => {
        ev.preventDefault();
        handleInput(key, true);
      };
      const release = (ev) => {
        ev.preventDefault();
        handleInput(key, false);
      };
      btn.addEventListener('touchstart', press, { passive: false });
      btn.addEventListener('touchend', release, { passive: false });
      btn.addEventListener('touchcancel', release, { passive: false });
      btn.addEventListener('mousedown', press);
      btn.addEventListener('mouseup', release);
      btn.addEventListener('mouseleave', release);
    });

    canvas.addEventListener('click', () => {
      if (gameState === 'menu' || gameState === 'gameover') {
        resetGame();
        gameState = 'playing';
      }
    });

    initStars();

    let lastTime = 0;
    function gameLoop(timestamp) {
      const deltaTime = Math.min(0.033, (timestamp - lastTime) / 1000 || 0);
      lastTime = timestamp;

      update(deltaTime);
      render();
      requestAnimationFrame(gameLoop);
    }

    requestAnimationFrame(gameLoop);
  </script>
</body>
</html>
